const path = require('path');

const app = express();
app.use(express.json()); // Allows your server to read incoming JSON data from users

// Serve static web pages from your project folder
app.use(express.static(__dirname));

// 1. Your digital address to MongoDB Atlas (Configured for cloud environment variables with local fallback)
